import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { returnsService } from '../services/returns';
import {
  Card, Alert, Button, FormField, Input, Select, Textarea, Spinner,
} from '../components/UI';
import { getErrorMessage } from '../utils/helpers';
import {
  Upload, X, Image as ImageIcon, CheckCircle2, AlertCircle,
  PackageOpen, Brain,
} from 'lucide-react';

export default function CreateReturnPage() {
  const navigate = useNavigate();
  const fileRef = useRef();

  const [form, setForm] = useState({
    order_id: '',
    product_name: '',
    delivery_date: '',
    return_reason: '',
    description: '',
  });
  const [images, setImages] = useState([]); // { file, preview, name }
  const [errors, setErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [apiError, setApiError] = useState('');
  const [submitted, setSubmitted] = useState(null);
  const [dragOver, setDragOver] = useState(false);

  const set = (k, v) => {
    setForm(p => ({ ...p, [k]: v }));
    if (errors[k]) setErrors(p => ({ ...p, [k]: '' }));
  };

  const validate = () => {
    const e = {};
    if (!form.order_id.trim()) e.order_id = 'Order ID is required';
    if (!form.product_name.trim()) e.product_name = 'Product name is required';
    if (!form.delivery_date) e.delivery_date = 'Delivery date is required';
    else if (new Date(form.delivery_date) > new Date()) e.delivery_date = 'Date cannot be in the future';
    if (!form.return_reason) e.return_reason = 'Please select a reason';
    if (!form.description.trim()) e.description = 'Description is required';
    else if (form.description.trim().length < 10) e.description = 'Please provide more detail (min 10 chars)';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const addImages = (files) => {
    const valid = Array.from(files).filter(f => f.type.startsWith('image/'));
    const newImgs = valid.slice(0, 5 - images.length).map(f => ({
      file: f,
      preview: URL.createObjectURL(f),
      name: f.name,
    }));
    setImages(p => [...p, ...newImgs]);
  };

  const removeImage = (i) => {
    URL.revokeObjectURL(images[i].preview);
    setImages(p => p.filter((_, idx) => idx !== i));
  };

  const handleDrop = (e) => {
    e.preventDefault(); setDragOver(false);
    addImages(e.dataTransfer.files);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validate()) return;
    setSubmitting(true); setApiError('');
    try {
      const fd = new FormData();
      Object.entries(form).forEach(([k, v]) => fd.append(k, v));
      images.forEach(img => fd.append('images', img.file));
      const res = await returnsService.createReturn(fd);
      setSubmitted(res.data);
    } catch (err) {
      setApiError(getErrorMessage(err));
    } finally {
      setSubmitting(false);
    }
  };

  // Success screen
  if (submitted) {
    const score = submitted.risk_score;
    const pct = Math.round(score * 100);
    const level = score < 0.3 ? 'LOW' : score < 0.55 ? 'MEDIUM' : score < 0.75 ? 'HIGH' : 'CRITICAL';
    const levelColor = { LOW: 'text-emerald-600', MEDIUM: 'text-amber-600', HIGH: 'text-red-600', CRITICAL: 'text-purple-600' }[level];

    return (
      <div className="max-w-xl mx-auto px-4 py-16 animate-slide-up">
        <Card className="p-8 text-center">
          <div className="w-14 h-14 bg-emerald-100 rounded-2xl flex items-center justify-center mx-auto mb-4">
            <CheckCircle2 className="w-8 h-8 text-emerald-600" />
          </div>
          <h2 className="font-display text-2xl font-bold text-slate-900">Request Submitted!</h2>
          <p className="text-slate-500 text-sm mt-2 mb-6">
            Your return request has been received and analyzed by our AI system.
          </p>

          <div className="bg-slate-50 rounded-xl p-4 text-left space-y-2 mb-6">
            <div className="flex justify-between text-sm">
              <span className="text-slate-500">Return ID</span>
              <span className="font-mono font-bold text-slate-900">#{submitted.id}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-500">Status</span>
              <span className="font-semibold capitalize text-brand-700">{submitted.status.replace('_', ' ')}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-500">Risk Level</span>
              <span className={`font-bold ${levelColor}`}>{level} ({pct}%)</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-500">Fraud Probability</span>
              <span className="font-mono font-semibold text-slate-700">{Math.round(submitted.fraud_probability * 100)}%</span>
            </div>
          </div>

          {submitted.risk_factors?.length > 0 && (
            <div className="bg-amber-50 border border-amber-100 rounded-xl p-4 text-left mb-6">
              <div className="flex items-center gap-2 mb-2">
                <AlertCircle className="w-4 h-4 text-amber-600" />
                <span className="text-xs font-bold text-amber-700">Risk Factors Detected</span>
              </div>
              <ul className="space-y-1">
                {submitted.risk_factors.map((f, i) => (
                  <li key={i} className="text-xs text-amber-700">• {f}</li>
                ))}
              </ul>
            </div>
          )}

          <div className="flex gap-3">
            <Button variant="secondary" className="flex-1" onClick={() => navigate('/customer/my-returns')}>
              View My Returns
            </Button>
            <Button className="flex-1" onClick={() => {
              setSubmitted(null);
              setForm({ order_id: '', product_name: '', delivery_date: '', return_reason: '', description: '' });
              setImages([]);
            }}>
              New Request
            </Button>
          </div>
        </Card>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto px-4 py-8 animate-fade-in">
      {/* Header */}
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-brand-50 rounded-xl">
          <PackageOpen className="w-5 h-5 text-brand-600" />
        </div>
        <div>
          <h1 className="font-display text-xl font-bold text-slate-900">Create Return Request</h1>
          <p className="text-slate-500 text-xs mt-0.5">Fill in the details below — our AI will analyze your submission</p>
        </div>
      </div>

      {/* AI Notice */}
      <div className="flex items-start gap-3 p-4 bg-indigo-50 border border-indigo-100 rounded-2xl mb-6">
        <Brain className="w-4 h-4 text-indigo-500 mt-0.5 flex-shrink-0" />
        <p className="text-xs text-indigo-700">
          <strong>AI-Powered Review:</strong> Your request will be analyzed using Isolation Forest anomaly detection, 
          a fraud classifier, and CNN-based image analysis to compute a risk score.
        </p>
      </div>

      {apiError && <Alert type="error" message={apiError} onClose={() => setApiError('')} className="mb-5" />}

      <form onSubmit={handleSubmit}>
        <Card className="p-6 space-y-5">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
            <FormField label="Order ID" error={errors.order_id} required>
              <Input
                value={form.order_id}
                onChange={e => set('order_id', e.target.value)}
                placeholder="e.g. ORD-2024-8821"
                error={errors.order_id}
              />
            </FormField>
            <FormField label="Product Name" error={errors.product_name} required>
              <Input
                value={form.product_name}
                onChange={e => set('product_name', e.target.value)}
                placeholder="e.g. Sony WH-1000XM5 Headphones"
                error={errors.product_name}
              />
            </FormField>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
            <FormField label="Delivery Date" error={errors.delivery_date} required hint="When did you receive the item?">
              <Input
                type="date"
                value={form.delivery_date}
                onChange={e => set('delivery_date', e.target.value)}
                max={new Date().toISOString().split('T')[0]}
                error={errors.delivery_date}
              />
            </FormField>
            <FormField label="Return Reason" error={errors.return_reason} required>
              <Select
                value={form.return_reason}
                onChange={e => set('return_reason', e.target.value)}
                error={errors.return_reason}
              >
                <option value="">Select a reason...</option>
                <option value="delivery_damaged">Delivery Damaged</option>
                <option value="not_working">Not Working</option>
                <option value="wrong_item">Wrong Item Received</option>
                <option value="other">Other</option>
              </Select>
            </FormField>
          </div>

          <FormField label="Description" error={errors.description} required hint="Describe the issue in detail for faster processing">
            <Textarea
              value={form.description}
              onChange={e => set('description', e.target.value)}
              placeholder="Please describe the issue with the product in detail..."
              rows={4}
              error={errors.description}
            />
          </FormField>

          {/* Image Upload */}
          <FormField label="Product Images" hint={`Upload up to 5 images. ${images.length}/5 uploaded.`}>
            <div
              onDragOver={e => { e.preventDefault(); setDragOver(true); }}
              onDragLeave={() => setDragOver(false)}
              onDrop={handleDrop}
              onClick={() => images.length < 5 && fileRef.current.click()}
              className={`border-2 border-dashed rounded-xl p-6 text-center cursor-pointer transition-colors
                ${dragOver ? 'border-brand-400 bg-brand-50' : 'border-slate-200 hover:border-brand-300 hover:bg-slate-50'}
                ${images.length >= 5 ? 'opacity-50 cursor-not-allowed' : ''}
              `}
            >
              <Upload className="w-6 h-6 text-slate-400 mx-auto mb-2" />
              <p className="text-sm font-medium text-slate-600">
                {dragOver ? 'Drop images here' : 'Click or drag & drop images'}
              </p>
              <p className="text-xs text-slate-400 mt-1">PNG, JPG, WEBP — each image will be analyzed by our CNN</p>
              <input
                ref={fileRef}
                type="file"
                multiple
                accept="image/*"
                className="hidden"
                onChange={e => addImages(e.target.files)}
              />
            </div>

            {/* Previews */}
            {images.length > 0 && (
              <div className="grid grid-cols-3 sm:grid-cols-5 gap-3 mt-3">
                {images.map((img, i) => (
                  <div key={i} className="relative group rounded-xl overflow-hidden border border-slate-200 aspect-square bg-slate-50">
                    <img src={img.preview} alt="" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                      <button
                        type="button"
                        onClick={e => { e.stopPropagation(); removeImage(i); }}
                        className="p-1 bg-white rounded-full"
                      >
                        <X className="w-3 h-3 text-slate-700" />
                      </button>
                    </div>
                    <div className="absolute bottom-1 left-1">
                      <ImageIcon className="w-3 h-3 text-white drop-shadow" />
                    </div>
                  </div>
                ))}
              </div>
            )}
          </FormField>
        </Card>

        <div className="mt-4 flex gap-3">
          <Button variant="secondary" className="flex-1" onClick={() => navigate(-1)} type="button">
            Cancel
          </Button>
          <Button type="submit" loading={submitting} className="flex-1 sm:flex-none sm:px-10" icon={Brain}>
            {submitting ? 'Analyzing with AI...' : 'Submit & Analyze'}
          </Button>
        </div>
      </form>
    </div>
  );
}
